def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity < 0:
            priorities[i] = np.inf
            continue
        if capacity == 0:
            priorities[i] = 0 if item == 0 else np.inf
            continue
        ratio = item / capacity if capacity != 0 else np.inf
        if item == 0 and capacity > 0:
            priorities[i] = 0
            continue
        if ratio < 0:
            priorities[i] = np.inf
            continue
        score = 0.0
        penalty = 0.0
        decay = 1.0
        extra_penalties = 0.0
        if ratio == 0:
            priorities[i] = 0
            continue
        if ratio > 3:
            for k in range(1, 6):
                penalty += (ratio ** (3 * k)) / (k ** 3 + 1)
            for j in range(1, 4):
                decay *= (1 - 1 / (ratio + j + 2))
            score = (ratio ** 5) / 4 + penalty
            if item > capacity * 4:
                score *= 3
            else:
                score *= 2
            priorities[i] = score * decay
        elif 2 < ratio <= 3:
            for x in range(1, 8):
                sign = (-1) ** (x + 1)
                score += sign * (ratio ** x) / (x + 2)
            for y in range(1, 5):
                decay *= (1 - 1 / (y + ratio + 3))
            score = abs(score) * decay * 12
            priorities[i] = score
        elif 1 < ratio <= 2:
            temp = 0
            for p in range(1, 12):
                if p % 2 == 0:
                    temp += (ratio ** p) / (p * 5)
                else:
                    temp -= (ratio ** p) / (p * 4)
            multiplier = 25 if ratio < 1.5 else 18 if ratio < 1.75 else 10
            score = abs(temp) * multiplier
            if ratio > 1.9:
                extra = 0
                for m in range(1, 6):
                    extra += (ratio ** m) / (m + 3)
                score += extra * 2
            priorities[i] = score
        elif 0 < ratio <= 1:
            temp_score = 0
            for p in range(1, 15):
                if p % 4 == 0:
                    temp_score += (ratio ** p) / (p * 3)
                elif p % 3 == 0:
                    temp_score += (ratio ** p) / (p * 6)
                else:
                    temp_score -= (ratio ** p) / (p * 5)
            if ratio < 0.2:
                multiplier = 30
            elif ratio < 0.4:
                multiplier = 22
            elif ratio < 0.6:
                multiplier = 15
            elif ratio < 0.8:
                multiplier = 8
            else:
                multiplier = 6
            score = abs(temp_score) * multiplier
            if ratio > 0.85:
                extra_penalties = 0
                for n in range(1, 7):
                    extra_penalties += (ratio ** n) / (n + 1)
                score += extra_penalties * 2
            priorities[i] = score
        else:
            if item == 0:
                priorities[i] = 0
            else:
                priorities[i] = np.inf
    for i in range(len(priorities)):
        if priorities[i] != np.inf and bins[i] > 0:
            factor = 1.0
            for z in range(1, 4):
                factor *= (1 + z / (bins[i] + 1))
            priorities[i] *= factor
        elif bins[i] <= 0:
            priorities[i] = np.inf
    return priorities
